iterate.script:
def title = doc.keySet().iterator().next()
def body = doc[title]
// skip if a doc with this title already exists for the tenant
def existingDoc = ec.entity.find('moqui.adk.AdkKnowledgeDoc')
    .condition('ownerPartyId', ownerPartyId).condition('title', title).one()
if (existingDoc == null) {
    try {
        ec.service.sync().name('AdkKnowledgeServices.ingest#AdkKnowledge')
            .parameters([ownerPartyId: ownerPartyId, title: title,
                         text: body, sourceType: 'policy']).call()
    } catch (Throwable t) {
        ec.logger.warn("Agent demo: knowledge ingest of '${title}' failed: ${t.message}")
    }
}
